static inline at::Tensor to_contiguous_half_if_needed(const at::Tensor& t) {
    at::Tensor x = t;
    if (x.scalar_type() != at::kHalf) {
        x = x.to(at::kHalf);
    }
    if (!x.is_contiguous()) {
        x = x.contiguous();
    }
    return x;
